function a(r,t="pt-BR",e="BRL"){return new Intl.NumberFormat(t,{style:"currency",currency:e}).format(r)}function s(r){const t=r.replace(/\D/g,"");if(!t)return"";if(t.length<=2)return t;const e=t.slice(-2);return t.slice(0,-2).replace(/\B(?=(\d{3})+(?!\d))/g,".")+"."+e}function c(r){if(!r)return 0;let t=String(r).trim();if(t.includes(","))t=t.replace(/\./g,""),t=t.replace(",",".");else{const e=t.lastIndexOf(".");if(e>-1){const n=t.substring(0,e).replace(/\./g,""),o=t.substring(e);t=n+o}}return parseFloat(t)}export{s as a,a as f,c as r};
